checker_dsl:
EXISTS (`variable V`) {
  AND {
    EXISTS (`file read expression FR`) {
      AND {
        (`V has an access A1`),
        EXISTS (`var access VA1`) {
          AND {
            (`VA1 is A1`),
            OR {
              EXISTS (`direct file read expression DFR`) {
                AND {
                  (`DFR is FR`),
                  OR {
                    EXISTS (`class instance expression CIE`) {
                      AND {
                        (`CIE is DFR`),
                        (`CIE argument 0 is VA1`),
                        OR {
                          (`CIE constructed type has qualified name "java.io.RandomAccessFile"`),
                          (`CIE constructed type has qualified name "java.io.FileReader"`),
                          (`CIE constructed type has qualified name "java.io.FileInputStream"`)
                        }
                      }
                    },
                    EXISTS (`method call MA`, `method FM`) {
                      AND {
                        (`MA is DFR`),
                        (`FM is MA's method`),
                        (`FM declaring type has qualified name "java.nio.file.Files"`),
                        (`MA argument 0 is VA1`),
                        OR {
                          (`FM has name "readAllBytes"`),
                          (`FM has name "readAllLines"`),
                          (`FM has name "readString"`),
                          (`FM has name "lines"`),
                          (`FM has name "newBufferedReader"`),
                          (`FM has name "newInputStream"`),
                          (`FM has name "newByteChannel"`)
                        }
                      }
                    }
                  }
                }
              },
              EXISTS (`call C`) {
                AND {
                  (`C is FR`),
                  EXISTS (`integer P`) {
                    AND {
                      EXISTS (`var access NVA1`) {
                        AND {
                          EXISTS (`file read expression FR2`) {
                            AND {
                              (`NVA1 has an access that is used in FR2`),
                              (`C's callee's parameter at position P is NVA1's variable`),
                              (`VA1 is C's argument at position P`)
                            }
                          }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    EXISTS (`set world writable expression SWW`) {
      AND {
        (`V has an access A2`),
        EXISTS (`var access VA2`) {
          AND {
            (`VA2 is A2`),
            OR {
              EXISTS (`method call FSW`) {
                AND {
                  (`FSW is SWW`),
                  (`FSW's method declaring type is TypeFile`),
                  (`FSW's method has name "setWritable"`),
                  NOT { (`FSW argument 0 is compile-time constant false`) },
                  (`FSW argument 1 is compile-time constant false`),
                  (`VA2 is FSW's qualifier`)
                }
              },
              EXISTS (`method call SPP`) {
                AND {
                  (`SPP is SWW`),
                  (`SPP's method has name "setPosixFilePermissions"`),
                  (`SPP's method declaring type has qualified name "java.nio.file.Files"`),
                  OR {
                    (`VA2 is SPP argument 0`),
                    EXISTS (`expression PE`) {
                      AND {
                        (`PE is SPP argument 0`),
                        (`PE's type is RefType with qualified name "java.nio.file.Path"`),
                        OR {
                          EXISTS (`method call FTP`) {
                            AND {
                              (`FTP is PE`),
                              (`VA2 is FTP's qualifier`),
                              (`FTP's method has name "toPath"`),
                              (`FTP's method declaring type is TypeFile`)
                            }
                          },
                          EXISTS (`method call PG`, `method call FGP`) {
                            AND {
                              (`PG is PE`),
                              (`PG's method has name "get"`),
                              (`PG's method declaring type has qualified name "java.nio.file.Paths"`),
                              (`FGP is PG argument 0`),
                              (`VA2 is FGP's qualifier`),
                              OR {
                                (`FGP's method has name "getPath"`),
                                (`FGP's method has name "getAbsolutePath"`),
                                (`FGP's method has name "getCanonicalPath"`)
                              }
                            }
                          }
                        }
                      }
                    }
                  },
                  EXISTS (`enum constant EC`) {
                    AND {
                      (`SPP argument 1 is an enum set reference ESR`),
                      (`ESR's type is RefType whose ancestor's source declaration has qualified name "java.util.Set"`),
                      OR {
                        EXISTS (`method call ESO`) {
                          AND {
                            (`ESO is ESR`),
                            (`ESO's method has name "of"`),
                            (`ESO's method declaring type's source declaration has qualified name "java.util.EnumSet"`),
                            (`EC is ESO's an argument as var access's variable`)
                          }
                        },
                        EXISTS (`var access ESA`) {
                          AND {
                            (`ESA is ESR`),
                            OR {
                              EXISTS (`expression AV`) {
                                AND {
                                  (`AV is ESA's variable's an assigned value`),
                                  (`EC is contained enum constant in AV`)
                                }
                              },
                              EXISTS (`method call ATS`) {
                                AND {
                                  (`ATS's qualifier is ESA's variable's an access`),
                                  OR {
                                    AND {
                                      (`ATS's method has name "add"`),
                                      (`EC is ATS argument 0 as var access's variable`)
                                    },
                                    AND {
                                      (`ATS's method has name "addAll"`),
                                      (`EC is contained enum constant in ATS argument 0`)
                                    }
                                  }
                                }
                              }
                            }
                          }
                        }
                      },
                      (`EC has name "OTHERS_WRITE"`)
                    }
                  }
                }
              },
              EXISTS (`call C2`) {
                AND {
                  (`C2 is SWW`),
                  EXISTS (`integer P2`) {
                    AND {
                      EXISTS (`var access NVA2`) {
                        AND {
                          EXISTS (`set world writable expression SWW2`) {
                            AND {
                              (`NVA2 has an access that is used in SWW2`),
                              (`C2's callee's parameter at position P2 is NVA2's variable`),
                              (`VA2 is C2's argument at position P2`)
                            }
                          }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    NOT { (`V is a Parameter`) }
  }
}
